sql:
SELECT table_name, key_column, value_column
FROM lookup_tables
WHERE lookup_table_category = 'product';

SELECT table_name
FROM lookup_tables
WHERE lookup_table_id = 1;

SELECT COUNT(*) AS total_access_count
FROM (
  SELECT access_id FROM lookup_table_access
  UNION ALL
  SELECT access_id FROM database_connection_access
);

SELECT created_at 
FROM database_connections 
ORDER BY created_at ASC;

SELECT user_id, access_date, access_device
FROM lookup_table_access
WHERE access_type = 'view';

external_knowledge:
- 'active lookup tables' refers to tables with an associated database connection status of 'active'; 
- 'most recently accessed' implies the access with the highest rank based on the access date; 
- 'within the last 30 days' refers to the time frame specified in the query.

sql:
SELECT COUNT(DISTINCT user_id) AS total_users_with_access
FROM (
    SELECT user_id FROM lookup_table_access
    UNION
    SELECT user_id FROM database_connection_access
);

SELECT COUNT(*) 
FROM database_connection_access 
WHERE user_id = 1;

SELECT 
    (SELECT COUNT(*) FROM lookup_table_access) + 
    (SELECT COUNT(*) FROM database_connection_access) AS total_accesses;
